{
  "name": "OmniTrack Pro - Advanced Issue & Downtime Management",
  "description": "A comprehensive issue tracking and system downtime analytics dashboard featuring real-time reporting, monthly aggregate data management, and interactive data visualizations."
}

export type Priority = 'Low' | 'Medium' | 'High';
export type Status = 'Open' | 'Close' | 'Pending' | 'In Progress' | 'Done';
export type IssueType = 'Software' | 'Device';
export type SystemType = 'CS' | 'HRM' | 'APP' | 'BEP' | 'ALL WITHOUT BEP' | 'All';

export interface Issue {
  id: string;
  client_name: string;
  issue_type: IssueType;
  priority: Priority;
  status: Status;
  assigned_person: string;
  issue_details: string;
  created_at: string;
  updated_at: string;
}

export interface MonthlyEntry {
  id: string;
  month: string; // YYYY-MM
  total_issues: number;
  system_bugs: number;
  device_issues: number;
  awareness: number;
  help_requests: number;
  created_at: string;
}

export interface SystemDowntime {
  id: string;
  date: string;
  system_name: SystemType;
  start_time: string;
  end_time: string;
  duration_minutes: number;
  created_at: string;
}

export type ViewType = 
  | 'Dashboard' 
  | 'IssueEntry' 
  | 'IssueReports' 
  | 'MonthlyEntry' 
  | 'MonthlyReports' 
  | 'DowntimeEntry' 
  | 'DowntimeReports';

import { Priority, Status, IssueType, SystemType } from './types';

export const ISSUE_TYPES: IssueType[] = ['Software', 'Device'];
export const PRIORITIES: Priority[] = ['Low', 'Medium', 'High'];
export const STATUSES: Status[] = ['Open', 'Close', 'Pending', 'In Progress', 'Done'];
export const ASSIGNED_PERSONS = ['Fuad', 'Rahat', 'Foysal', 'Taqi', 'Fariha'];
export const SYSTEMS: SystemType[] = ['CS', 'HRM', 'APP', 'BEP', 'ALL WITHOUT BEP', 'All'];

export const PRIORITY_COLORS = {
  Low: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800',
  Medium: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 border-amber-200 dark:border-amber-800',
  High: 'bg-rose-100 text-rose-700 dark:bg-rose-900/30 dark:text-rose-400 border-rose-200 dark:border-rose-800',
};

export const STATUS_COLORS = {
  Open: 'bg-blue-100 text-blue-700 border-blue-200',
  Close: 'bg-slate-100 text-slate-700 border-slate-200',
  Pending: 'bg-orange-100 text-orange-700 border-orange-200',
  'In Progress': 'bg-purple-100 text-purple-700 border-purple-200',
  Done: 'bg-emerald-100 text-emerald-700 border-emerald-200',
};

export const CHART_COLORS = ['#6366f1', '#a855f7', '#ec4899', '#f97316', '#10b981'];

import { Issue, MonthlyEntry, SystemDowntime } from '../types';

// This service is built to be easily replaced with Supabase calls.
// For the purpose of this functional demo, it uses localStorage to ensure it works out of the box.

const getStored = <T,>(key: string): T[] => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : [];
};

const setStored = <T,>(key: string, data: T[]): void => {
  localStorage.setItem(key, JSON.stringify(data));
};

export const dbService = {
  // Issues
  async getIssues(): Promise<Issue[]> {
    return getStored<Issue>('issues');
  },
  async saveIssue(issue: Omit<Issue, 'id' | 'created_at' | 'updated_at'>): Promise<Issue> {
    const issues = getStored<Issue>('issues');
    const newIssue: Issue = {
      ...issue,
      id: Math.random().toString(36).substr(2, 9),
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
    };
    setStored('issues', [newIssue, ...issues]);
    return newIssue;
  },
  async updateIssue(id: string, updates: Partial<Issue>): Promise<Issue> {
    const issues = getStored<Issue>('issues');
    const index = issues.findIndex(i => i.id === id);
    if (index === -1) throw new Error('Issue not found');
    const updated = { ...issues[index], ...updates, updated_at: new Date().toISOString() };
    issues[index] = updated;
    setStored('issues', issues);
    return updated;
  },
  async deleteIssue(id: string): Promise<void> {
    const issues = getStored<Issue>('issues');
    setStored('issues', issues.filter(i => i.id !== id));
  },

  // Monthly Entries
  async getMonthlyEntries(): Promise<MonthlyEntry[]> {
    return getStored<MonthlyEntry>('monthly_entries');
  },
  async saveMonthlyEntry(entry: Omit<MonthlyEntry, 'id' | 'created_at'>): Promise<MonthlyEntry> {
    const entries = getStored<MonthlyEntry>('monthly_entries');
    const newEntry: MonthlyEntry = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9),
      created_at: new Date().toISOString(),
    };
    setStored('monthly_entries', [newEntry, ...entries]);
    return newEntry;
  },
  async updateMonthlyEntry(id: string, updates: Partial<MonthlyEntry>): Promise<MonthlyEntry> {
    const entries = getStored<MonthlyEntry>('monthly_entries');
    const index = entries.findIndex(e => e.id === id);
    const updated = { ...entries[index], ...updates };
    entries[index] = updated;
    setStored('monthly_entries', entries);
    return updated;
  },
  async deleteMonthlyEntry(id: string): Promise<void> {
    const entries = getStored<MonthlyEntry>('monthly_entries');
    setStored('monthly_entries', entries.filter(e => e.id !== id));
  },

  // System Downtime
  async getDowntime(): Promise<SystemDowntime[]> {
    return getStored<SystemDowntime>('system_downtime');
  },
  async saveDowntime(entry: Omit<SystemDowntime, 'id' | 'created_at'>): Promise<SystemDowntime> {
    const data = getStored<SystemDowntime>('system_downtime');
    const newEntry: SystemDowntime = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9),
      created_at: new Date().toISOString(),
    };
    setStored('system_downtime', [newEntry, ...data]);
    return newEntry;
  },
  async deleteDowntime(id: string): Promise<void> {
    const data = getStored<SystemDowntime>('system_downtime');
    setStored('system_downtime', data.filter(d => d.id !== id));
  }
};

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  PlusCircle, 
  FileText, 
  Calendar, 
  BarChart3, 
  Clock, 
  History,
  Menu,
  X,
  Sun,
  Moon,
  ShieldCheck
} from 'lucide-react';
import { ViewType } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeView: ViewType;
  onNavigate: (view: ViewType) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeView, onNavigate }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    return localStorage.getItem('theme') === 'dark' || 
      (!localStorage.getItem('theme') && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const navItems = [
    { id: 'Dashboard', icon: LayoutDashboard, label: 'Dashboard' },
    { id: 'divider', type: 'divider', label: 'Issues' },
    { id: 'IssueEntry', icon: PlusCircle, label: 'Issue Entry' },
    { id: 'IssueReports', icon: FileText, label: 'Issue Reports' },
    { id: 'divider2', type: 'divider', label: 'Monthly Tracking' },
    { id: 'MonthlyEntry', icon: Calendar, label: 'Monthly Entry' },
    { id: 'MonthlyReports', icon: BarChart3, label: 'Monthly Reports' },
    { id: 'divider3', type: 'divider', label: 'Infrastructure' },
    { id: 'DowntimeEntry', icon: Clock, label: 'Downtime Entry' },
    { id: 'DowntimeReports', icon: History, label: 'Downtime Reports' },
  ];

  return (
    <div className="flex min-h-screen bg-slate-50 dark:bg-slate-950">
      {/* Sidebar */}
      <aside 
        className={`fixed inset-y-0 left-0 z-50 w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transition-transform duration-300 lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}
      >
        <div className="flex flex-col h-full">
          {/* Logo */}
          <div className="p-6 flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl gradient-bg flex items-center justify-center text-white shadow-lg">
              <ShieldCheck size={24} />
            </div>
            <div>
              <h1 className="font-bold text-xl tracking-tight text-slate-900 dark:text-white">OmniTrack</h1>
              <span className="text-xs font-medium text-slate-500 uppercase tracking-widest">Enterprise</span>
            </div>
          </div>

          {/* Navigation */}
          <nav className="flex-1 px-4 py-4 space-y-1 overflow-y-auto">
            {navItems.map((item) => {
              if (item.type === 'divider') {
                return (
                  <div key={item.id} className="px-3 pt-6 pb-2">
                    <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">
                      {item.label}
                    </span>
                  </div>
                );
              }

              const Icon = item.icon!;
              const isActive = activeView === item.id;

              return (
                <button
                  key={item.id}
                  onClick={() => onNavigate(item.id as ViewType)}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all ${
                    isActive 
                      ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 shadow-sm' 
                      : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-white'
                  }`}
                >
                  <Icon size={18} className={isActive ? 'text-indigo-600 dark:text-indigo-400' : ''} />
                  {item.label}
                </button>
              );
            })}
          </nav>

          {/* User & Theme */}
          <div className="p-4 border-t border-slate-200 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50">
            <button 
              onClick={() => setIsDarkMode(!isDarkMode)}
              className="w-full flex items-center justify-between gap-3 px-3 py-2 rounded-lg text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
            >
              <div className="flex items-center gap-3">
                {isDarkMode ? <Moon size={18} /> : <Sun size={18} />}
                <span>{isDarkMode ? 'Dark Mode' : 'Light Mode'}</span>
              </div>
              <div className={`w-8 h-4 rounded-full relative transition-colors ${isDarkMode ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                 <div className={`absolute top-0.5 w-3 h-3 rounded-full bg-white transition-all ${isDarkMode ? 'left-4.5' : 'left-0.5'}`} />
              </div>
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className={`flex-1 transition-all duration-300 ${isSidebarOpen ? 'lg:ml-64' : ''}`}>
        {/* Header */}
        <header className="sticky top-0 z-30 flex items-center justify-between px-6 py-4 bg-white/80 dark:bg-slate-950/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800">
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-500 lg:hidden"
            >
              {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
            </button>
            <h2 className="text-lg font-semibold text-slate-900 dark:text-white">
              {navItems.find(i => i.id === activeView)?.label || 'OmniTrack'}
            </h2>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-100 dark:bg-slate-800 rounded-full">
              <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
              <span className="text-xs font-medium text-slate-600 dark:text-slate-300">System Online</span>
            </div>
            <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-800 flex items-center justify-center overflow-hidden">
               <img src="https://picsum.photos/seed/user/100" alt="Avatar" />
            </div>
          </div>
        </header>

        {/* Page Content */}
        <div className="p-6">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend,
  LineChart, Line, AreaChart, Area
} from 'recharts';
import { 
  AlertCircle, 
  Bug, 
  Smartphone, 
  Lightbulb, 
  HelpCircle, 
  Activity,
  ArrowUpRight,
  ArrowDownRight,
  ChevronDown
} from 'lucide-react';
import { dbService } from '../services/dbService';
import { Issue, MonthlyEntry, SystemDowntime } from '../types';
import { CHART_COLORS } from '../constants';

const Dashboard: React.FC = () => {
  const [issues, setIssues] = useState<Issue[]>([]);
  const [monthlyEntries, setMonthlyEntries] = useState<MonthlyEntry[]>([]);
  const [downtime, setDowntime] = useState<SystemDowntime[]>([]);
  const [selectedMonth, setSelectedMonth] = useState<string>(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
  });

  useEffect(() => {
    const fetchData = async () => {
      const [i, m, d] = await Promise.all([
        dbService.getIssues(),
        dbService.getMonthlyEntries(),
        dbService.getDowntime(),
      ]);
      setIssues(i);
      setMonthlyEntries(m);
      setDowntime(d);
    };
    fetchData();
  }, []);

  // Filter and process data
  const filteredIssues = issues.filter(issue => issue.created_at.startsWith(selectedMonth));
  const currentMonthlyEntry = monthlyEntries.find(e => e.month === selectedMonth);

  // Metrics
  const stats = [
    { label: 'Total Issues', value: currentMonthlyEntry?.total_issues || filteredIssues.length, icon: AlertCircle, color: 'text-indigo-600', bg: 'bg-indigo-100 dark:bg-indigo-900/20' },
    { label: 'System Bugs', value: currentMonthlyEntry?.system_bugs || filteredIssues.filter(i => i.issue_details.toLowerCase().includes('bug')).length, icon: Bug, color: 'text-rose-600', bg: 'bg-rose-100 dark:bg-rose-900/20' },
    { label: 'Device Issues', value: currentMonthlyEntry?.device_issues || filteredIssues.filter(i => i.issue_type === 'Device').length, icon: Smartphone, color: 'text-amber-600', bg: 'bg-amber-100 dark:bg-amber-900/20' },
    { label: 'Awareness', value: currentMonthlyEntry?.awareness || 0, icon: Lightbulb, color: 'text-emerald-600', bg: 'bg-emerald-100 dark:bg-emerald-900/20' },
    { label: 'Help Requests', value: currentMonthlyEntry?.help_requests || 0, icon: HelpCircle, color: 'text-sky-600', bg: 'bg-sky-100 dark:bg-sky-900/20' },
    { label: 'System Downtime', value: `${(downtime.filter(d => d.date.startsWith(selectedMonth)).reduce((acc, d) => acc + d.duration_minutes, 0) / 60).toFixed(1)}h`, icon: Activity, color: 'text-fuchsia-600', bg: 'bg-fuchsia-100 dark:bg-fuchsia-900/20' },
  ];

  // Frequent Issue Companies
  const companyCounts = filteredIssues.reduce((acc, issue) => {
    acc[issue.client_name] = (acc[issue.client_name] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const frequentCompanies = Object.entries(companyCounts)
    .filter(([_, count]) => count >= 2)
    .sort((a, b) => b[1] - a[1]);

  // Chart Data
  const issueTypeData = [
    { name: 'System Bug', value: currentMonthlyEntry?.system_bugs || filteredIssues.filter(i => i.issue_details.toLowerCase().includes('bug')).length },
    { name: 'Device Issue', value: currentMonthlyEntry?.device_issues || filteredIssues.filter(i => i.issue_type === 'Device').length },
    { name: 'Awareness', value: currentMonthlyEntry?.awareness || 0 },
    { name: 'Help Request', value: currentMonthlyEntry?.help_requests || 0 },
  ].filter(d => d.value > 0);

  const statusData = ['Open', 'Close', 'Pending', 'In Progress', 'Done'].map(status => ({
    name: status,
    count: filteredIssues.filter(i => i.status === status).length
  }));

  const downtimeTimeline = downtime
    .filter(d => d.date.startsWith(selectedMonth))
    .map(d => ({
      date: d.date.split('-')[2],
      duration: d.duration_minutes,
      system: d.system_name
    }));

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Header & Filter */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Performance Overview</h1>
          <p className="text-slate-500 dark:text-slate-400">Track and analyze system health and issues</p>
        </div>
        <div className="flex items-center gap-2 bg-white dark:bg-slate-900 p-1.5 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <span className="text-xs font-bold text-slate-400 pl-2 uppercase">Period</span>
          <select 
            value={selectedMonth}
            onChange={(e) => setSelectedMonth(e.target.value)}
            className="bg-transparent text-sm font-semibold outline-none pr-2 cursor-pointer text-indigo-600"
          >
            {Array.from({ length: 12 }, (_, i) => {
              const d = new Date();
              d.setMonth(d.getMonth() - i);
              const val = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
              return (
                <option key={val} value={val}>
                  {d.toLocaleString('default', { month: 'long', year: 'numeric' })}
                </option>
              );
            })}
          </select>
        </div>
      </div>

      {/* Metrics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm hover:shadow-md transition-shadow">
            <div className={`w-10 h-10 ${stat.bg} rounded-xl flex items-center justify-center mb-4`}>
              <stat.icon size={20} className={stat.color} />
            </div>
            <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{stat.label}</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">{stat.value}</h3>
          </div>
        ))}
      </div>

      {/* Middle Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Frequent Companies */}
        <div className="lg:col-span-1 bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-bold text-slate-900 dark:text-white">Frequent Reporters</h3>
            <span className="text-[10px] px-2 py-0.5 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-full font-bold uppercase">Critical</span>
          </div>
          <div className="space-y-4">
            {frequentCompanies.length > 0 ? frequentCompanies.map(([name, count], i) => (
              <div key={name} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-lg bg-white dark:bg-slate-900 flex items-center justify-center text-xs font-bold text-slate-400">#{i+1}</div>
                  <span className="text-sm font-semibold text-slate-700 dark:text-slate-300">{name}</span>
                </div>
                <div className="flex items-center gap-1.5 px-2 py-1 bg-rose-50 dark:bg-rose-900/20 text-rose-600 dark:text-rose-400 rounded-lg text-xs font-bold">
                  <ArrowUpRight size={14} />
                  {count} Issues
                </div>
              </div>
            )) : (
              <div className="py-12 text-center text-slate-400">
                <p className="text-sm">No frequent reports this month</p>
              </div>
            )}
          </div>
        </div>

        {/* Issue Distribution Pie */}
        <div className="lg:col-span-1 bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm min-h-[350px]">
          <h3 className="font-bold text-slate-900 dark:text-white mb-6">Distribution by Type</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={issueTypeData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {issueTypeData.map((_, index) => (
                    <Cell key={`cell-${index}`} fill={CHART_COLORS[index % CHART_COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
                  itemStyle={{ color: '#fff' }}
                />
                <Legend iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Status Breakdown Bar */}
        <div className="lg:col-span-1 bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm min-h-[350px]">
          <h3 className="font-bold text-slate-900 dark:text-white mb-6">Status Breakdown</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={statusData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 600 }} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 600 }} />
                <Tooltip 
                  cursor={{ fill: 'rgba(226, 232, 240, 0.4)' }}
                  contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
                />
                <Bar dataKey="count" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={32} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Downtime Timeline Chart */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h3 className="font-bold text-slate-900 dark:text-white">System Downtime Timeline</h3>
            <p className="text-sm text-slate-500">Duration by system across the month</p>
          </div>
          <div className="flex gap-4">
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-full bg-rose-500" />
              <span className="text-xs font-medium text-slate-500">Critical Duration</span>
            </div>
          </div>
        </div>
        <div className="h-80">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={downtimeTimeline.length > 0 ? downtimeTimeline : [{date: '01', duration: 0}, {date: '30', duration: 0}]}>
              <defs>
                <linearGradient id="colorDur" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#f43f5e" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
              <XAxis dataKey="date" axisLine={false} tickLine={false} label={{ value: 'Day of Month', position: 'insideBottom', offset: -5, fontSize: 10 }} />
              <YAxis axisLine={false} tickLine={false} unit="m" />
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
                labelFormatter={(label) => `Day: ${label}`}
              />
              <Area 
                type="monotone" 
                dataKey="duration" 
                stroke="#f43f5e" 
                strokeWidth={3}
                fillOpacity={1} 
                fill="url(#colorDur)" 
                animationDuration={1500}
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { dbService } from '../services/dbService';
import { ISSUE_TYPES, PRIORITIES, STATUSES, ASSIGNED_PERSONS } from '../constants';
import { IssueType, Priority, Status } from '../types';
import { CheckCircle, AlertCircle } from 'lucide-react';

const IssueEntry: React.FC = () => {
  const [formData, setFormData] = useState({
    client_name: '',
    issue_type: 'Software' as IssueType,
    priority: 'Medium' as Priority,
    status: 'Open' as Status,
    assigned_person: ASSIGNED_PERSONS[0],
    issue_details: '',
  });

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setSuccess(false);

    // Simple validation
    if (!formData.client_name || !formData.issue_details) {
      setError('Please fill in all required fields.');
      setIsLoading(false);
      return;
    }

    try {
      await dbService.saveIssue(formData);
      setSuccess(true);
      setFormData({
        client_name: '',
        issue_type: 'Software',
        priority: 'Medium',
        status: 'Open',
        assigned_person: ASSIGNED_PERSONS[0],
        issue_details: '',
      });
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      setError('Failed to save issue. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto animate-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl overflow-hidden">
