      ]);
      setIssues(i);
      setMonthlyEntries(m);
      setDowntime(d);
    };
    fetchData();
  }, []);

  const filteredIssues = issues.filter(issue => issue.created_at.startsWith(selectedMonth));
  const currentMonthlyEntry = monthlyEntries.find(e => e.month === selectedMonth);

  const stats = [
    { label: 'Total Issues', value: currentMonthlyEntry?.total_issues || filteredIssues.length, icon: AlertCircle, color: '#6366f1', glow: 'shadow-indigo-500/20' },
    { label: 'System Bugs', value: currentMonthlyEntry?.system_bugs || filteredIssues.filter(i => i.issue_details.toLowerCase().includes('bug')).length, icon: Bug, color: '#f43f5e', glow: 'shadow-rose-500/20' },
    { label: 'Device Issues', value: currentMonthlyEntry?.device_issues || filteredIssues.filter(i => i.issue_type === 'Device').length, icon: Smartphone, color: '#fbbf24', glow: 'shadow-amber-500/20' },
    { label: 'Awareness', value: currentMonthlyEntry?.awareness || 0, icon: Lightbulb, color: '#10b981', glow: 'shadow-emerald-500/20' },
    { label: 'Help Requests', value: currentMonthlyEntry?.help_requests || 0, icon: HelpCircle, color: '#0ea5e9', glow: 'shadow-sky-500/20' },
    { label: 'Downtime', value: `${(downtime.filter(d => d.date.startsWith(selectedMonth)).reduce((acc, d) => acc + d.duration_minutes, 0) / 60).toFixed(1)}h`, icon: Activity, color: '#d946ef', glow: 'shadow-fuchsia-500/20' },
  ];

  const companyCounts = filteredIssues.reduce((acc, issue) => {
    acc[issue.client_name] = (acc[issue.client_name] || 0) + 1;
