    acc[issue.client_name] = (acc[issue.client_name] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const frequentCompanies = Object.entries(companyCounts)
    .filter(([_, count]) => count >= 2)
    .sort((a, b) => b[1] - a[1]);

  const issueTypeData = [
    { name: 'System Bug', value: currentMonthlyEntry?.system_bugs || filteredIssues.filter(i => i.issue_details.toLowerCase().includes('bug')).length },
    { name: 'Device Issue', value: currentMonthlyEntry?.device_issues || filteredIssues.filter(i => i.issue_type === 'Device').length },
    { name: 'Awareness', value: currentMonthlyEntry?.awareness || 0 },
    { name: 'Help Request', value: currentMonthlyEntry?.help_requests || 0 },
  ].filter(d => d.value > 0);

  const downtimeTimeline = downtime
    .filter(d => d.date.startsWith(selectedMonth))
    .map(d => ({
      date: d.date.split('-')[2],
      duration: d.duration_minutes,
      system: d.system_name
    }));

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-2 duration-700">
      {/* Header Area */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight">Executive Dashboard</h1>
          <p className="text-slate-500 mt-2 font-medium">Real-time intelligence and system health monitoring.</p>
        </div>
        <div className="flex items-center gap-3 p-2 bg-white border border-slate-200 rounded-2xl shadow-sm">
          <span className="text-[10px] font-bold text-slate-400 pl-3 uppercase tracking-widest">Reporting Month</span>
          <select 
            value={selectedMonth}
            onChange={(e) => setSelectedMonth(e.target.value)}
            className="bg-slate-50 text-blue-600 font-bold px-4 py-2 rounded-xl outline-none border border-blue-100 cursor-pointer hover:bg-white hover:border-blue-400 transition-all"
          >
            {Array.from({ length: 12 }, (_, i) => {
              const d = new Date();
              d.setMonth(d.getMonth() - i);
              const val = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
              return (
                <option key={val} value={val}>
                  {d.toLocaleString('default', { month: 'long', year: 'numeric' })}
                </option>
              );
            })}
          </select>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className={`bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm transition-all hover:scale-105 hover:shadow-md group`}>
            <div className="flex justify-between items-start mb-6">
              <div className={`p-3 ${stat.bg} rounded-2xl group-hover:scale-110 transition-transform`}>
                <stat.icon size={24} style={{ color: stat.color }} />
              </div>
              <TrendingUp size={16} className="text-emerald-500 opacity-0 group-hover:opacity-100 transition-opacity" />
            </div>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.15em] mb-1">{stat.label}</p>
            <h3 className="text-3xl font-bold text-slate-900 tracking-tighter">{stat.value}</h3>
          </div>
        ))}
      </div>

      {/* Content Sections */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Frequent Companies List */}
        <div className="lg:col-span-4 bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-8">
             <div className="flex items-center gap-3">
               <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center text-blue-600">
                  <Box size={20} />
               </div>
               <h3 className="font-bold text-lg text-slate-900">Repeat Incidents</h3>
             </div>
             <span className="text-[10px] bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full font-bold uppercase tracking-widest border border-emerald-100">Monthly</span>
          </div>
          <div className="space-y-4">
            {frequentCompanies.length > 0 ? frequentCompanies.map(([name, count], i) => (
              <div key={name} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 hover:border-blue-200 transition-all cursor-default group">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-xl bg-white border border-slate-200 flex items-center justify-center text-xs font-bold text-blue-600">
                    {i+1}
                  </div>
                  <div>
                    <span className="text-sm font-bold text-slate-900 block">{name}</span>
                    <span className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Enterprise Client</span>
                  </div>
                </div>
                <div className="flex flex-col items-end">
                  <span className="text-sm font-black text-blue-600">{count}</span>
                  <span className="text-[8px] text-slate-400 font-bold uppercase">Reports</span>
                </div>
              </div>
            )) : (
              <div className="py-20 text-center text-slate-400">
                <p className="text-sm font-bold italic">No recurring issues found.</p>
              </div>
            )}
          </div>
        </div>

        {/* Issue Distribution Chart */}
        <div className="lg:col-span-8 bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm min-h-[450px]">
          <div className="flex items-center justify-between mb-10">
            <div>
              <h3 className="font-bold text-xl text-slate-900">Issue Composition</h3>
              <p className="text-xs text-slate-500 mt-1 font-medium tracking-wide">Breakdown of reported categories for current period</p>
            </div>
          </div>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={issueTypeData}>
                <defs>
                  <linearGradient id="colorIssues" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#2563eb" stopOpacity={0.2}/>
                    <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" stroke="#94a3b8" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold' }} />
                <YAxis stroke="#94a3b8" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold' }} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#ffffff', border: '1px solid #e2e8f0', borderRadius: '16px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }}
                />
                <Area type="monotone" dataKey="value" stroke="#2563eb" strokeWidth={3} fillOpacity={1} fill="url(#colorIssues)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Large Timeline Chart */}
      <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm">
        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-12 gap-4">
          <div>
            <h3 className="font-bold text-2xl text-slate-900">System Downtime Analytics</h3>
            <p className="text-sm text-slate-500 mt-1 font-medium">Interruption duration mapped against monthly timeline</p>
          </div>
          <div className="flex items-center gap-6 p-4 bg-slate-50 rounded-2xl border border-slate-100">
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-full bg-blue-600 shadow-lg shadow-blue-200" />
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Active Tracking</span>
            </div>
            <div className="h-4 w-px bg-slate-200" />
            <div className="text-right">
              <span className="text-[10px] font-bold text-slate-400 block uppercase">Peak Delay</span>
              <span className="text-sm font-black text-slate-900">
                {Math.max(...downtimeTimeline.map(d => d.duration), 0)} min
              </span>
            </div>
          </div>
        </div>
        <div className="h-96">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={downtimeTimeline.length > 0 ? downtimeTimeline : [{date: '01', duration: 0}]}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="date" stroke="#94a3b8" axisLine={false} tickLine={false} tick={{ fontSize: 10 }} />
              <YAxis stroke="#94a3b8" axisLine={false} tickLine={false} unit="m" tick={{ fontSize: 10 }} />
              <Tooltip 
                cursor={{ fill: '#f8fafc' }}
                contentStyle={{ backgroundColor: '#ffffff', border: '1px solid #e2e8f0', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)' }}
              />
              <Bar dataKey="duration" fill="#2563eb" radius={[6, 6, 0, 0]} barSize={32} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

