import React, { useState } from 'react';
import { dbService } from '../services/dbService';
import { ISSUE_TYPES, PRIORITIES, STATUSES, ASSIGNED_PERSONS } from '../constants';
import { IssueType, Priority, Status } from '../types';
import { CheckCircle, AlertCircle, FilePlus } from 'lucide-react';

const IssueEntry: React.FC = () => {
  const [formData, setFormData] = useState({
    client_name: '',
    issue_type: 'Software' as IssueType,
    priority: 'Medium' as Priority,
    status: 'Open' as Status,
    assigned_person: ASSIGNED_PERSONS[0],
    issue_details: '',
  });

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setSuccess(false);

    if (!formData.client_name || !formData.issue_details) {
      setError('Please fill in all required fields.');
      setIsLoading(false);
      return;
    }

    try {
      await dbService.saveIssue(formData);
      setSuccess(true);
      setFormData({
        client_name: '',
        issue_type: 'Software',
        priority: 'Medium',
        status: 'Open',
        assigned_person: ASSIGNED_PERSONS[0],
        issue_details: '',
      });
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      setError('Failed to save issue. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto animate-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white rounded-3xl border border-slate-200 shadow-lg shadow-slate-100 overflow-hidden">
        <div className="bg-slate-50 p-8 border-b border-slate-100 flex items-center justify-between">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">New Incident Report</h2>
            <p className="text-slate-500 text-sm mt-1">Submit a detailed report for the technical team.</p>
          </div>
          <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center shadow-inner">
            <FilePlus size={24} />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          {error && (
            <div className="flex items-center gap-2 p-4 bg-rose-50 text-rose-600 rounded-xl border border-rose-100 text-sm">
              <AlertCircle size={18} />
              {error}
            </div>
          )}

          {success && (
            <div className="flex items-center gap-2 p-4 bg-emerald-50 text-emerald-600 rounded-xl border border-emerald-100 text-sm">
              <CheckCircle size={18} />
              Issue submitted successfully!
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700">Client Name *</label>
              <input 
                type="text"
                value={formData.client_name}
                onChange={(e) => setFormData({...formData, client_name: e.target.value})}
                placeholder="e.g. Acme Corp"
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all text-slate-900"
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700">Issue Type *</label>
              <select 
                value={formData.issue_type}
                onChange={(e) => setFormData({...formData, issue_type: e.target.value as IssueType})}
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all text-slate-900"
              >
                {ISSUE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700">Priority *</label>
              <select 
                value={formData.priority}
                onChange={(e) => setFormData({...formData, priority: e.target.value as Priority})}
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all text-slate-900"
              >
                {PRIORITIES.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700">Assigned To *</label>
              <select 
                value={formData.assigned_person}
                onChange={(e) => setFormData({...formData, assigned_person: e.target.value})}
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all text-slate-900"
              >
                {ASSIGNED_PERSONS.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700">Issue Details *</label>
            <textarea 
              rows={4}
              value={formData.issue_details}
              onChange={(e) => setFormData({...formData, issue_details: e.target.value})}
              placeholder="Provide a thorough description..."
              className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all text-slate-900 resize-none"
            />
          </div>

          <button 
            type="submit"
            disabled={isLoading}
            className="w-full py-4 gradient-bg text-white font-bold rounded-xl shadow-lg shadow-blue-100 hover:opacity-90 active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
          >
            {isLoading ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : 'Submit Issue Report'}
          </button>
        </form>
      </div>
    </div>
  );
};

