import React, { useState } from 'react';
import { dbService } from '../services/dbService';
import { CheckCircle, AlertCircle, CalendarRange } from 'lucide-react';

const MonthlyEntry: React.FC = () => {
  const [formData, setFormData] = useState({
    month: `${new Date().getFullYear()}-${String(new Date().getMonth() + 1).padStart(2, '0')}`,
    total_issues: 0,
    system_bugs: 0,
    device_issues: 0,
    awareness: 0,
    help_requests: 0,
  });

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setSuccess(false);

    try {
      await dbService.saveMonthlyEntry(formData);
      setSuccess(true);
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      setError('Failed to save monthly summary.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto animate-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-xl shadow-slate-100 overflow-hidden">
        <div className="bg-slate-50 p-10 border-b border-slate-100 flex items-center justify-between">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Monthly Performance</h2>
            <p className="text-slate-500 text-sm mt-1 font-medium">Consolidated analytics for official reporting.</p>
          </div>
          <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center border border-blue-100">
            <CalendarRange size={24} />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-10 space-y-8">
          {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl border border-rose-100 text-sm font-semibold">{error}</div>}
          {success && <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl border border-emerald-100 text-sm font-semibold">Data synchronized successfully!</div>}

          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Reporting Period</label>
              <input 
                type="month"
                value={formData.month}
                onChange={(e) => setFormData({...formData, month: e.target.value})}
                className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-900 font-bold focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
              />
            </div>

            <div className="grid grid-cols-2 gap-6">
              {[
                { label: 'Total Issues', key: 'total_issues', color: 'text-blue-600' },
                { label: 'System Bugs', key: 'system_bugs', color: 'text-rose-600' },
                { label: 'Device Issues', key: 'device_issues', color: 'text-amber-600' },
                { label: 'Awareness', key: 'awareness', color: 'text-emerald-600' },
                { label: 'Help Requests', key: 'help_requests', color: 'text-sky-600' },
              ].map(field => (
                <div key={field.key} className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.15em]">{field.label}</label>
                  <input 
                    type="number"
                    value={formData[field.key as keyof typeof formData]}
                    onChange={(e) => setFormData({...formData, [field.key]: parseInt(e.target.value) || 0})}
                    className={`w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl font-black text-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all ${field.color}`}
                  />
                </div>
              ))}
            </div>
          </div>

          <button 
            type="submit"
            className="w-full py-5 gradient-bg text-white font-black text-lg rounded-2xl shadow-lg shadow-blue-100 hover:opacity-90 active:scale-[0.98] transition-all"
          >
            Update Reporting Data
          </button>
        </form>
      </div>
    </div>
  );
};

