                <p className="text-2xl font-black text-rose-600">{e.system_bugs}</p>
              </div>
              <div>
                <p className="text-[10px] text-slate-400 font-bold uppercase">Device</p>
                <p className="text-2xl font-black text-amber-600">{e.device_issues}</p>
