                <p className="text-[10px] text-slate-400 font-bold uppercase">Help</p>
                <p className="text-2xl font-black text-sky-600">{e.help_requests}</p>
              </div>
            </div>
          </div>
        ))}
        {entries.length === 0 && (
           <div className="col-span-full py-12 text-center bg-slate-50 rounded-[2rem] border border-dashed border-slate-200 text-slate-400 font-medium">
             No monthly data available. Please submit a summary.
           </div>
        )}
