          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Month</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Issues</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">System Bugs</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Device</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Awareness</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {entries.map((e, idx) => (
                <tr key={e.id} className="hover:bg-slate-50/80 transition-all group">
                  <td className="px-8 py-5 font-bold text-slate-900">
                    {new Date(e.month + '-01').toLocaleString('default', { month: 'long', year: 'numeric' })}
                  </td>
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <span className="font-black text-slate-900">{e.total_issues}</span>
                      {getComparison(idx, 'total_issues')}
                    </div>
                  </td>
                  <td className="px-8 py-5 text-sm font-semibold text-rose-600">{e.system_bugs}</td>
                  <td className="px-8 py-5 text-sm font-semibold text-amber-600">{e.device_issues}</td>
                  <td className="px-8 py-5 text-sm font-semibold text-emerald-600">{e.awareness}</td>
                  <td className="px-8 py-5 text-right">
                    <button 
                      onClick={() => handleDelete(e.id)}
                      className="text-slate-300 hover:text-rose-500 hover:bg-rose-50 p-2 rounded-xl transition-all"
                    >
                      <Trash2 size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

