    { label: 'Awareness', value: currentMonthlyEntry?.awareness || 0, icon: Lightbulb, color: '#10b981', bg: 'bg-emerald-50/50' },
    { label: 'Help Requests', value: currentMonthlyEntry?.help_requests || 0, icon: HelpCircle, color: '#0ea5e9', bg: 'bg-sky-50/50' },
    { label: 'Downtime', value: `${(downtime.filter(d => d.date.startsWith(selectedMonth)).reduce((acc, d) => acc + d.duration_minutes, 0) / 60).toFixed(1)}h`, icon: Activity, color: '#f43f5e', bg: 'bg-rose-50/50' },
  ];

  const companyCounts = filteredIssues.reduce((acc, issue) => {
    acc[issue.client_name] = (acc[issue.client_name] || 0) + 1;
