          <div className="w-16 h-16 bg-blue-600 text-white rounded-3xl flex items-center justify-center shadow-2xl shadow-blue-200">
            <CalendarRange size={30} strokeWidth={2.5} />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-12 space-y-10">
          {error && <div className="p-5 bg-rose-50 text-rose-600 rounded-2xl border border-rose-100 text-sm font-black flex items-center gap-3"><AlertCircle size={20} /> {error}</div>}
          {success && <div className="p-5 bg-emerald-50 text-emerald-600 rounded-2xl border border-emerald-100 text-sm font-black flex items-center gap-3"><CheckCircle size={20} /> Database Update Successful!</div>}

          <div className="space-y-8">
            <div className="space-y-3">
              <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Selected Reporting Period</label>
              <input 
                type="month"
                value={formData.month}
                onChange={(e) => setFormData({...formData, month: e.target.value})}
                className="w-full px-6 py-5 bg-white border border-slate-200 rounded-3xl text-slate-900 font-black text-xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none transition-all shadow-sm"
              />
            </div>

            <div className="grid grid-cols-2 gap-6">
              {inputFields.map(field => (
                <div key={field.key} className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">{field.label}</label>
                  <div className={`relative ${field.bg} rounded-[2rem] border-2 ${field.border} p-1 group transition-all hover:border-blue-400`}>
                    <input 
                      type="number"
                      value={formData[field.key as keyof typeof formData]}
                      onChange={(e) => setFormData({...formData, [field.key]: parseInt(e.target.value) || 0})}
                      className={`w-full px-6 py-4 bg-white rounded-[1.6rem] font-black text-2xl outline-none transition-all ${field.color} shadow-inner`}
                    />
                  </div>
                </div>
              ))}
            </div>
          </div>

          <button 
            type="submit"
            disabled={isLoading}
            className="w-full py-6 gradient-bg text-white font-black text-xl rounded-[2rem] shadow-2xl shadow-blue-200 hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-50"
          >
            {isLoading ? 'Processing Cloud Update...' : 'Update Monthly Repository'}
          </button>
        </form>
      </div>
    </div>
  );
};

