import React, { useState, useEffect } from 'react';
import { dbService } from '../services/dbService';
import { MonthlyEntry } from '../types';
import { Trash2, TrendingUp, TrendingDown, Minus, BarChart3, ChevronRight } from 'lucide-react';

const MonthlyReports: React.FC = () => {
  const [entries, setEntries] = useState<MonthlyEntry[]>([]);

  useEffect(() => {
    loadEntries();
  }, []);

  const loadEntries = async () => {
    const data = await dbService.getMonthlyEntries();
    setEntries(data.sort((a, b) => b.month.localeCompare(a.month)));
  };

  const handleDelete = async (id: string) => {
    if (confirm('Permanently remove this monthly summary from server?')) {
      await dbService.deleteMonthlyEntry(id);
      loadEntries();
    }
  };

  const getComparison = (index: number, key: keyof MonthlyEntry) => {
    if (index >= entries.length - 1) return null;
    const current = entries[index][key] as number;
    const prev = entries[index + 1][key] as number;
    if (current > prev) return <div className="flex items-center gap-1 text-rose-500"><TrendingUp size={14} /> <span className="text-[10px] font-black">Up</span></div>;
    if (current < prev) return <div className="flex items-center gap-1 text-emerald-500"><TrendingDown size={14} /> <span className="text-[10px] font-black">Down</span></div>;
    return <Minus size={14} className="text-slate-300" />;
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-1000">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Performance <span className="text-blue-600">Archive</span></h2>
          <p className="text-slate-500 mt-2 font-semibold text-lg">Cross-month comparative analysis of system integrity.</p>
        </div>
        <div className="px-6 py-3 glass rounded-2xl text-blue-600 text-xs font-black uppercase tracking-[0.2em] border-blue-100 border flex items-center gap-3">
          <BarChart3 size={18} strokeWidth={2.5} />
          Analytical Mode
        </div>
      </div>

      {/* Overview Comparison Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        {entries.slice(0, 4).map(e => (
          <div key={e.id} className="glass-card p-10 rounded-[3rem] transition-all duration-500 hover:shadow-xl group relative overflow-hidden">
            <div className="absolute top-0 right-0 w-24 h-24 bg-blue-50/50 rounded-bl-full -mr-12 -mt-12 transition-all group-hover:w-32 group-hover:h-32" />

            <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] mb-8 flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-blue-600" />
              {new Date(e.month + '-01').toLocaleString('default', { month: 'long', year: 'numeric' })}
            </h4>

            <div className="grid grid-cols-2 gap-y-10">
              <div className="space-y-1">
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Aggregate</p>
                <p className="text-3xl font-black text-slate-900 tracking-tighter">{e.total_issues}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Crit. Bugs</p>
                <p className="text-3xl font-black text-rose-600 tracking-tighter">{e.system_bugs}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Hardw.</p>
                <p className="text-3xl font-black text-amber-600 tracking-tighter">{e.device_issues}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Support</p>
                <p className="text-3xl font-black text-sky-600 tracking-tighter">{e.help_requests}</p>
              </div>
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 flex items-center justify-between">
               <span className="text-[10px] font-black text-slate-400 uppercase">Analysis Ready</span>
               <ChevronRight size={16} className="text-blue-300" />
            </div>
          </div>
        ))}
        {entries.length === 0 && (
           <div className="col-span-full py-32 text-center glass-card rounded-[3rem] border-dashed border-2 border-slate-200 text-slate-400 font-bold italic">
             Database is empty. Awaiting monthly synchronization.
           </div>
        )}
      </div>

      {/* History Ledger */}
      <div className="glass-card rounded-[3.5rem] shadow-sm overflow-hidden">
        <div className="p-10 border-b border-slate-100 bg-white/40">
          <h3 className="font-black text-2xl text-slate-900 tracking-tight">System Ledger History</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Cycle Period</th>
                <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Aggregated Issues</th>
                <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Bugs / Device</th>
                <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Internal Awareness</th>
                <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] text-right">Server Action</th>
              </tr>
            </thead>
