                  <td className="px-10 py-7">
                    <div className="flex items-center gap-2">
                      <span className="text-base font-black text-rose-600">{e.system_bugs}</span>
                      <span className="text-slate-300">/</span>
                      <span className="text-base font-black text-amber-600">{e.device_issues}</span>
                    </div>
                  </td>
                  <td className="px-10 py-7">
                    <div className="flex items-center gap-4">
                      <span className="text-base font-black text-emerald-600">{e.awareness}</span>
                      {getComparison(idx, 'awareness')}
                    </div>
                  </td>
                  <td className="px-10 py-7 text-right">
                    <button 
                      onClick={() => handleDelete(e.id)}
                      className="text-slate-300 hover:text-rose-600 hover:bg-rose-50 p-3 rounded-2xl transition-all group-hover:shadow-inner"
                    >
                      <Trash2 size={20} strokeWidth={2.5} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

