import React, { useState, useEffect } from 'react';
import { dbService } from '../services/dbService';
import { SYSTEMS } from '../constants';
import { SystemType } from '../types';
import { Clock, Activity, ShieldAlert } from 'lucide-react';

const DowntimeEntry: React.FC = () => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    system_name: 'APP' as SystemType,
    start_time: '09:00',
    end_time: '10:00',
    duration_minutes: 60,
  });

  const [isLoading, setIsLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    const start = new Date(`${formData.date}T${formData.start_time}`);
    const end = new Date(`${formData.date}T${formData.end_time}`);
    let diff = (end.getTime() - start.getTime()) / (1000 * 60);
    if (diff < 0) diff += 1440; // Handles overnight downtime
    setFormData(prev => ({ ...prev, duration_minutes: Math.round(diff) }));
  }, [formData.start_time, formData.end_time, formData.date]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      await dbService.saveDowntime(formData);
      setSuccess(true);
      setTimeout(() => setSuccess(false), 3000);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto animate-in slide-in-from-bottom-6 duration-700">
      <div className="glass-card rounded-[3.5rem] overflow-hidden">
        <div className="bg-white/40 p-12 border-b border-white flex items-center justify-between">
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Incident Log</h2>
            <p className="text-slate-500 text-base mt-2 font-semibold">Record service interruptions for root-cause analysis.</p>
          </div>
          <div className="w-16 h-16 bg-rose-600 text-white rounded-3xl flex items-center justify-center shadow-2xl shadow-rose-200">
            <ShieldAlert size={30} strokeWidth={2.5} />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-12 space-y-8">
          {success && (
             <div className="p-5 bg-emerald-50 text-emerald-600 rounded-2xl border border-emerald-100 text-sm font-black flex items-center gap-3 animate-in fade-in">
               <Activity size={20} /> Downtime Incident Synchronized!
             </div>
          )}

          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Incident Date</label>
              <input 
                type="date"
                value={formData.date}
                onChange={(e) => setFormData({...formData, date: e.target.value})}
                className="w-full px-6 py-4 bg-white border border-slate-200 rounded-2xl text-slate-900 font-black focus:ring-4 focus:ring-rose-50 outline-none transition-all shadow-sm"
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Affected Infrastructure</label>
              <select 
                value={formData.system_name}
                onChange={(e) => setFormData({...formData, system_name: e.target.value as SystemType})}
                className="w-full px-6 py-4 bg-white border border-slate-200 rounded-2xl text-slate-900 font-black focus:ring-4 focus:ring-rose-50 outline-none transition-all shadow-sm cursor-pointer"
              >
                {SYSTEMS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">From (Start)</label>
                <input 
                  type="time"
                  value={formData.start_time}
                  onChange={(e) => setFormData({...formData, start_time: e.target.value})}
                  className="w-full px-6 py-4 bg-white border border-slate-200 rounded-2xl text-slate-900 font-black focus:ring-4 focus:ring-rose-50 outline-none transition-all shadow-sm"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">To (End)</label>
                <input 
                  type="time"
                  value={formData.end_time}
                  onChange={(e) => setFormData({...formData, end_time: e.target.value})}
                  className="w-full px-6 py-4 bg-white border border-slate-200 rounded-2xl text-slate-900 font-black focus:ring-4 focus:ring-rose-50 outline-none transition-all shadow-sm"
                />
              </div>
            </div>

            <div className="p-6 bg-rose-50 rounded-[2rem] border-2 border-dashed border-rose-100 flex items-center justify-between">
              <div className="flex items-center gap-3 text-rose-600">
                <Clock size={24} />
                <span className="text-sm font-black uppercase tracking-widest">Total Delay</span>
              </div>
              <span className="text-2xl font-black text-rose-700">{formData.duration_minutes} Minutes</span>
            </div>
          </div>

          <button 
            type="submit"
            disabled={isLoading}
            className="w-full py-6 bg-rose-600 text-white font-black text-xl rounded-[2rem] shadow-2xl shadow-rose-200 hover:bg-rose-700 hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-50 flex items-center justify-center gap-3"
          >
            {isLoading ? <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin" /> : 'Confirm Log Entry'}
          </button>
        </form>
      </div>
    </div>
  );
};

