import { Plus, Trash2, Settings as SettingsIcon, Layers, UserPlus, Database, Activity, Tag } from 'lucide-react';

const CATEGORIES = [
  { id: 'assigned_persons', label: 'Assigned Persons', icon: UserPlus, color: 'text-blue-600' },
  { id: 'systems', label: 'System List', icon: Database, color: 'text-indigo-600' },
  { id: 'issue_types', label: 'Issue Types', icon: Layers, color: 'text-purple-600' },
  { id: 'priorities', label: 'Priority Levels', icon: Activity, color: 'text-rose-600' },
  { id: 'statuses', label: 'System Statuses', icon: Tag, color: 'text-emerald-600' },
] as const;

const Settings: React.FC = () => {
  const [settings, setSettings] = useState<SettingItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<typeof CATEGORIES[number]['id']>('assigned_persons');
  const [newItem, setNewItem] = useState('');

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    const data = await dbService.getSettings();
    setSettings(data);
  };

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim()) return;
    await dbService.saveSetting({
      category: activeCategory,
      label: newItem.trim(),
      value: newItem.trim(),
    });
    setNewItem('');
    loadSettings();
  };

  const handleDelete = async (id: string) => {
    await dbService.deleteSetting(id);
    loadSettings();
  };

  const currentSettings = settings.filter(s => s.category === activeCategory);

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
