      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* Category Selector */}
        <div className="lg:col-span-4 space-y-4">
          {CATEGORIES.map((cat) => (
            <button
              key={cat.id}
              onClick={() => setActiveCategory(cat.id)}
              className={`w-full flex items-center justify-between p-6 rounded-[2rem] border transition-all duration-300 ${
                activeCategory === cat.id 
                  ? 'bg-white border-blue-200 shadow-xl shadow-blue-50/50 scale-[1.02]' 
                  : 'bg-white/40 border-slate-100 hover:bg-white hover:border-slate-200'
