                </div>
                <span className={`font-black tracking-tight ${activeCategory === cat.id ? 'text-slate-900' : 'text-slate-500'}`}>
                  {cat.label}
                </span>
              </div>
              {activeCategory === cat.id && <div className="w-2 h-2 rounded-full bg-blue-600" />}
            </button>
          ))}
        </div>

        {/* Content Area */}
        <div className="lg:col-span-8 glass-card p-10 rounded-[3rem] shadow-sm flex flex-col min-h-[500px]">
