          <form onSubmit={handleAdd} className="flex gap-4 mb-10">
            <input 
              type="text"
              value={newItem}
              onChange={(e) => setNewItem(e.target.value)}
              placeholder={`Add new ${activeCategory.replace('_', ' ')}...`}
