import React, { useState, useEffect } from 'react';
import { dbService } from '../services/dbService';
import { SettingItem } from '../types';
import { CheckCircle, AlertCircle, PlusCircle } from 'lucide-react';

const IssueEntry: React.FC = () => {
  const [settings, setSettings] = useState<SettingItem[]>([]);
  const [formData, setFormData] = useState({
    client_name: '',
    issue_type: '',
    priority: '',
    status: '',
    assigned_person: '',
    issue_details: '',
  });

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    const data = await dbService.getSettings();
    setSettings(data);
    // Set defaults from dynamic data
    setFormData(prev => ({
      ...prev,
      issue_type: data.find(s => s.category === 'issue_types')?.value || '',
      priority: data.find(s => s.category === 'priorities')?.value || '',
      status: data.find(s => s.category === 'statuses')?.value || '',
      assigned_person: data.find(s => s.category === 'assigned_persons')?.value || '',
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setSuccess(false);

    if (!formData.client_name || !formData.issue_details) {
      setError('Required fields are missing.');
      setIsLoading(false);
      return;
    }

    try {
      await dbService.saveIssue(formData);
      setSuccess(true);
      setFormData(prev => ({ ...prev, client_name: '', issue_details: '' }));
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      setError('Database synchronization failed.');
    } finally {
      setIsLoading(false);
    }
  };

  const filter = (cat: SettingItem['category']) => settings.filter(s => s.category === cat);

  return (
    <div className="max-w-3xl mx-auto animate-in slide-in-from-bottom-6 duration-700">
      <div className="glass-card rounded-[3.5rem] overflow-hidden">
        <div className="gradient-bg p-12 text-white">
          <div className="flex items-center justify-between">
            <div>
               <h2 className="text-4xl font-black tracking-tight">Incident Report</h2>
               <p className="opacity-80 text-lg mt-2 font-medium">Capture system irregularities for immediate team review.</p>
            </div>
            <PlusCircle size={50} strokeWidth={1.5} className="opacity-50" />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-12 space-y-8">
          {error && <div className="p-5 bg-rose-50 text-rose-600 rounded-3xl border border-rose-100 text-sm font-black flex items-center gap-3"><AlertCircle size={20} /> {error}</div>}
          {success && <div className="p-5 bg-emerald-50 text-emerald-600 rounded-3xl border border-emerald-100 text-sm font-black flex items-center gap-3"><CheckCircle size={20} /> Incident Synchronized Successfully!</div>}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-3">
              <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Client Entity</label>
              <input 
                type="text"
                value={formData.client_name}
                onChange={(e) => setFormData({...formData, client_name: e.target.value})}
                placeholder="e.g. Acme Enterprise"
                className="w-full px-6 py-4 bg-white border border-slate-200 rounded-2xl font-bold focus:ring-4 focus:ring-blue-50 focus:border-blue-500 outline-none transition-all shadow-sm"
              />
            </div>

            <div className="space-y-3">
              <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Classification</label>
              <select 
                value={formData.issue_type}
                onChange={(e) => setFormData({...formData, issue_type: e.target.value})}
                className="w-full px-6 py-4 bg-white border border-slate-200 rounded-2xl font-bold focus:ring-4 focus:ring-blue-50 outline-none transition-all shadow-sm cursor-pointer"
              >
                {filter('issue_types').map(s => <option key={s.id} value={s.value}>{s.label}</option>)}
              </select>
            </div>

            <div className="space-y-3">
              <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Priority Matrix</label>
              <select 
                value={formData.priority}
                onChange={(e) => setFormData({...formData, priority: e.target.value})}
                className="w-full px-6 py-4 bg-white border border-slate-200 rounded-2xl font-bold focus:ring-4 focus:ring-blue-50 outline-none transition-all shadow-sm cursor-pointer"
              >
                {filter('priorities').map(s => <option key={s.id} value={s.value}>{s.label}</option>)}
              </select>
            </div>

            <div className="space-y-3">
              <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Assigned Personnel</label>
              <select 
                value={formData.assigned_person}
                onChange={(e) => setFormData({...formData, assigned_person: e.target.value})}
                className="w-full px-6 py-4 bg-white border border-slate-200 rounded-2xl font-bold focus:ring-4 focus:ring-blue-50 outline-none transition-all shadow-sm cursor-pointer"
              >
                {filter('assigned_persons').map(s => <option key={s.id} value={s.value}>{s.label}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Incident Specifics</label>
            <textarea 
              rows={5}
              value={formData.issue_details}
              onChange={(e) => setFormData({...formData, issue_details: e.target.value})}
              placeholder="Describe the technical variance or failure point..."
              className="w-full px-6 py-5 bg-white border border-slate-200 rounded-[2rem] font-medium focus:ring-4 focus:ring-blue-50 focus:border-blue-500 outline-none transition-all shadow-sm resize-none"
