];

export const dbService = {
  // Settings
  async getSettings(): Promise<SettingItem[]> {
    let settings = getStored<SettingItem>('settings');
    if (settings.length === 0) {
      settings = INITIAL_SETTINGS.map(s => ({
        ...s,
        id: Math.random().toString(36).substr(2, 9),
        created_at: new Date().toISOString()
      }));
      setStored('settings', settings);
    }
    return settings;
  },
  async getSettingsByCategory(category: SettingItem['category']): Promise<SettingItem[]> {
    const settings = await this.getSettings();
    return settings.filter(s => s.category === category);
  },
  async saveSetting(setting: Omit<SettingItem, 'id' | 'created_at'>): Promise<SettingItem> {
    const settings = getStored<SettingItem>('settings');
    const newSetting: SettingItem = {
      ...setting,
      id: Math.random().toString(36).substr(2, 9),
      created_at: new Date().toISOString()
    };
    setStored('settings', [...settings, newSetting]);
    return newSetting;
  },
  async deleteSetting(id: string): Promise<void> {
    const settings = getStored<SettingItem>('settings');
    setStored('settings', settings.filter(s => s.id !== id));
  },

  // Issues
  async getIssues(): Promise<Issue[]> {
    return getStored<Issue>('issues');
  },
  async saveIssue(issue: Omit<Issue, 'id' | 'created_at' | 'updated_at'>): Promise<Issue> {
    const issues = getStored<Issue>('issues');
    const newIssue: Issue = {
      ...issue,
      id: Math.random().toString(36).substr(2, 9),
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
    };
    setStored('issues', [newIssue, ...issues]);
    return newIssue;
  },
  async updateIssue(id: string, updates: Partial<Issue>): Promise<Issue> {
    const issues = getStored<Issue>('issues');
    const index = issues.findIndex(i => i.id === id);
    if (index === -1) throw new Error('Issue not found');
    const updated = { ...issues[index], ...updates, updated_at: new Date().toISOString() };
    issues[index] = updated;
    setStored('issues', issues);
    return updated;
  },
  async deleteIssue(id: string): Promise<void> {
    const issues = getStored<Issue>('issues');
    setStored('issues', issues.filter(i => i.id !== id));
  },

  // Monthly Entries
  async getMonthlyEntries(): Promise<MonthlyEntry[]> {
    return getStored<MonthlyEntry>('monthly_entries');
  },
  async saveMonthlyEntry(entry: Omit<MonthlyEntry, 'id' | 'created_at'>): Promise<MonthlyEntry> {
    const entries = getStored<MonthlyEntry>('monthly_entries');
    const newEntry: MonthlyEntry = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9),
      created_at: new Date().toISOString(),
    };
    setStored('monthly_entries', [newEntry, ...entries]);
    return newEntry;
  },
  async updateMonthlyEntry(id: string, updates: Partial<MonthlyEntry>): Promise<MonthlyEntry> {
    const entries = getStored<MonthlyEntry>('monthly_entries');
    const index = entries.findIndex(e => e.id === id);
    const updated = { ...entries[index], ...updates };
    entries[index] = updated;
    setStored('monthly_entries', entries);
    return updated;
  },
  async deleteMonthlyEntry(id: string): Promise<void> {
    const entries = getStored<MonthlyEntry>('monthly_entries');
    setStored('monthly_entries', entries.filter(e => e.id !== id));
  },

  // System Downtime
  async getDowntime(): Promise<SystemDowntime[]> {
    return getStored<SystemDowntime>('system_downtime');
  },
  async saveDowntime(entry: Omit<SystemDowntime, 'id' | 'created_at'>): Promise<SystemDowntime> {
    const data = getStored<SystemDowntime>('system_downtime');
    const newEntry: SystemDowntime = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9),
      created_at: new Date().toISOString(),
    };
    setStored('system_downtime', [newEntry, ...data]);
    return newEntry;
  },
  async deleteDowntime(id: string): Promise<void> {
    const data = getStored<SystemDowntime>('system_downtime');
    setStored('system_downtime', data.filter(d => d.id !== id));
  }
};

import React, { useState, useEffect } from 'react';
import { dbService } from '../services/dbService';
import { SettingItem } from '../types';
import { Plus, Trash2, Settings as SettingsIcon } from 'lucide-react';

const CATEGORIES: { id: SettingItem['category']; label: string }[] = [
  { id: 'issue_type', label: 'Issue Types' },
  { id: 'priority', label: 'Priorities' },
  { id: 'status', label: 'Statuses' },
  { id: 'assigned_person', label: 'Assigned Persons' },
  { id: 'system_name', label: 'Systems' },
];

const Settings: React.FC = () => {
  const [settings, setSettings] = useState<SettingItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<SettingItem['category']>('issue_type');
  const [newName, setNewName] = useState('');

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    const data = await dbService.getSettings();
    setSettings(data);
  };

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName.trim()) return;
    await dbService.saveSetting({ category: activeCategory, name: newName.trim() });
    setNewName('');
    loadSettings();
  };

  const handleDelete = async (id: string) => {
    if (confirm('Are you sure you want to delete this option?')) {
      await dbService.deleteSetting(id);
      loadSettings();
    }
  };

  const currentCategorySettings = settings.filter(s => s.category === activeCategory);

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-500">
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl overflow-hidden">
        <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex items-center gap-4">
          <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl flex items-center justify-center">
            <SettingsIcon size={24} />
          </div>
          <div>
            <h2 className="text-2xl font-bold dark:text-white">System Settings</h2>
            <p className="text-slate-500 text-sm">Manage dropdown options for all entry pages.</p>
          </div>
        </div>

        <div className="flex flex-col md:flex-row">
          {/* Sidebar Tabs */}
          <div className="w-full md:w-64 border-r border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 p-4 space-y-1">
            {CATEGORIES.map(cat => (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                className={`w-full text-left px-4 py-3 rounded-xl text-sm font-semibold transition-all ${
                  activeCategory === cat.id
                    ? 'bg-white dark:bg-slate-800 text-indigo-600 dark:text-indigo-400 shadow-sm border border-slate-200 dark:border-slate-700'
                    : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
                }`}
              >
                {cat.label}
              </button>
            ))}
          </div>

          {/* Main Content */}
          <div className="flex-1 p-8 space-y-6">
            <form onSubmit={handleAdd} className="flex gap-3">
              <input
                type="text"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                placeholder={`Add new ${CATEGORIES.find(c => c.id === activeCategory)?.label.toLowerCase()}...`}
                className="flex-1 px-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all dark:text-white"
              />
              <button
                type="submit"
                className="px-6 py-2.5 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 transition-colors flex items-center gap-2"
              >
                <Plus size={18} />
                Add
              </button>
            </form>

            <div className="bg-slate-50 dark:bg-slate-800/30 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden">
              <table className="w-full text-left">
                <thead>
                  <tr className="border-b border-slate-200 dark:border-slate-800">
                    <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Option Name</th>
                    <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-200 dark:divide-slate-800">
                  {currentCategorySettings.length > 0 ? (
                    currentCategorySettings.map(item => (
                      <tr key={item.id} className="hover:bg-white dark:hover:bg-slate-800/50 transition-colors">
                        <td className="px-6 py-4 text-sm font-medium dark:text-white">{item.name}</td>
                        <td className="px-6 py-4 text-right">
                          <button
                            onClick={() => handleDelete(item.id)}
                            className="p-2 text-slate-400 hover:text-rose-600 transition-colors"
                          >
                            <Trash2 size={16} />
                          </button>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={2} className="px-6 py-8 text-center text-slate-400 text-sm italic">
                        No options added for this category yet.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Settings;

