const SYSTEM_INSTRUCTION = `You are a Site Uptime Monitoring & Incident Analysis AI.
Target website: https://hrm.tipsoi.pro

You will receive status check data every 30 seconds from an external script.
Each input will contain:
- timestamp (ISO format)
- http_status (number or null)
- response_time_ms (number or null)
- success (true/false)
- error_message (string or null)

Your responsibilities:

1. CLASSIFY STATUS
- If success = true and http_status is 200–399 → status = "UP"
- If success = false OR http_status is null OR http_status >= 400 → status = "DOWN"

2. INCIDENT DETECTION
- If status becomes DOWN after being UP → mark as "NEW INCIDENT"
- If status remains DOWN → mark as "ONGOING INCIDENT"
- If status becomes UP after DOWN → mark as "RECOVERED"

3. INCIDENT LOGIC
- Track:
  - incident_start_time
  - incident_end_time
  - total_downtime_duration (seconds)
- Multiple DOWN checks within one continuous period count as ONE incident

4. ALERT DECISION (VERY IMPORTANT)
- Trigger "ALERT_REQUIRED = true" when:
  - A NEW INCIDENT starts
- Trigger "RECOVERY_NOTICE = true" when:
  - Site recovers from DOWN to UP
- Otherwise keep both false

5. OUTPUT FORMAT (STRICT JSON)
Always respond ONLY in this JSON format:
{
  "timestamp": "",
  "status": "UP | DOWN",
  "incident_state": "NONE | NEW INCIDENT | ONGOING INCIDENT | RECOVERED",
  "alert_required": true | false,
  "recovery_notice": true | false,
  "message": "",
  "summary": ""
}

6. MESSAGE RULES
- Message should be short, clear, professional
Examples:
- "hrm.tipsoi.pro is DOWN (no response). Incident started at 10:12 AM."
- "hrm.tipsoi.pro has RECOVERED. Total downtime: 6 minutes."

7. ANALYTICS MODE
When user asks questions like:
- "How many times was the site down today?"
- "Longest downtime this week?"
- "Most frequent downtime hour?"

Analyze all provided logs and answer clearly with numbers and timestamps.
Never hallucinate data. If logs are insufficient, clearly say so.
You are precise, reliable, and production-grade.`;

const LiveMonitoring: React.FC = () => {
  const [logs, setLogs] = useState<MonitoringLog[]>([]);
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{ role: 'user' | 'ai', text: string }[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    loadLogs();
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatHistory]);

  const loadLogs = async () => {
    const data = await dbService.getMonitoringLogs();
    setLogs(data);
  };

  const runCheck = async () => {
    if (!isMonitoring) return;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Simulation: Generate a check
    // Randomly fail 10% of the time for simulation purposes
    const isSuccess = Math.random() > 0.1;
    const checkData = {
      timestamp: new Date().toISOString(),
      http_status: isSuccess ? 200 : (Math.random() > 0.5 ? 500 : 404),
      response_time_ms: isSuccess ? Math.floor(Math.random() * 500) + 100 : null,
      success: isSuccess,
      error_message: isSuccess ? null : "Connection Timeout"
    };

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Previous logs for context: ${JSON.stringify(logs.slice(0, 5))}\n\nNEW CHECK DATA:\n${JSON.stringify(checkData)}`,
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const analysis = JSON.parse(response.text || '{}');
      const newLog: Omit<MonitoringLog, 'id'> = {
        ...checkData,
        ai_analysis: analysis
      };

      const savedLog = await dbService.saveMonitoringLog(newLog);
      setLogs(prev => [savedLog, ...prev].slice(0, 500));

    } catch (err) {
      console.error("AI Monitoring Error:", err);
    }
  };

  useEffect(() => {
    let interval: any;
    if (isMonitoring) {
      runCheck(); // Run immediate first check
      interval = setInterval(runCheck, 30000);
    }
    return () => clearInterval(interval);
  }, [isMonitoring]);

  const handleAskAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatMessage.trim() || isChatLoading) return;

    setIsChatLoading(true);
    const userText = chatMessage;
    setChatHistory(prev => [...prev, { role: 'user', text: userText }]);
    setChatMessage('');

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `LOG DATA FOR ANALYSIS:\n${JSON.stringify(logs)}\n\nUSER QUESTION:\n${userText}`,
        config: {
          systemInstruction: SYSTEM_INSTRUCTION
        }
      });

      setChatHistory(prev => [...prev, { role: 'ai', text: response.text || "No analysis available." }]);
    } catch (err) {
      setChatHistory(prev => [...prev, { role: 'ai', text: "Sorry, I encountered an error analyzing the logs." }]);
    } finally {
      setIsChatLoading(false);
    }
  };

  const currentStatus = logs[0]?.ai_analysis?.status || 'UNKNOWN';

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header Panel */}
      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl overflow-hidden">
