} from 'lucide-react';

const SYSTEM_INSTRUCTION = `You are a Site Uptime Monitoring & Incident Analysis AI.

You will receive status check data periodically from an external script.
Each input will contain:
- timestamp (ISO format)
- http_status (number or null)
- response_time_ms (number or null)
- success (true/false)
- error_message (string or null)

Your responsibilities:

1. CLASSIFY STATUS
- If success = true and http_status is 200–399 → status = "UP"
- If success = false OR http_status is null OR http_status >= 400 → status = "DOWN"

2. INCIDENT DETECTION
- If status becomes DOWN after being UP → mark as "NEW INCIDENT"
- If status remains DOWN → mark as "ONGOING INCIDENT"
- If status becomes UP after DOWN → mark as "RECOVERED"

3. INCIDENT LOGIC
- Track:
  - incident_start_time
  - incident_end_time
  - total_downtime_duration (seconds)
- Multiple DOWN checks within one continuous period count as ONE incident

4. ALERT DECISION (VERY IMPORTANT)
- Trigger "ALERT_REQUIRED = true" when:
  - A NEW INCIDENT starts
- Trigger "RECOVERY_NOTICE = true" when:
  - Site recovers from DOWN to UP
- Otherwise keep both false

5. OUTPUT FORMAT (STRICT JSON)
Always respond ONLY in this JSON format:
{
  "timestamp": "",
  "status": "UP | DOWN",
  "incident_state": "NONE | NEW INCIDENT | ONGOING INCIDENT | RECOVERED",
  "alert_required": true | false,
  "recovery_notice": true | false,
  "message": "",
  "summary": ""
}

6. MESSAGE RULES
- Message should be short, clear, professional.
- Mention the target URL provided in the context.

Never hallucinate data. You are precise, reliable, and production-grade.`;

const LiveMonitoring: React.FC = () => {
  const [logs, setLogs] = useState<MonitoringLog[]>([]);
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [targetUrl, setTargetUrl] = useState('https://hrm.tipsoi.pro');
  const [frequency, setFrequency] = useState(30); // seconds
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  useEffect(() => {
    loadLogs();
  }, []);

  const loadLogs = async () => {
    const data = await dbService.getMonitoringLogs();
    setLogs(data);
  };

  const runCheck = async () => {
    if (!isMonitoring) return;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Simulation: Generate a check
    // Randomly fail 5% of the time for simulation purposes
    const isSuccess = Math.random() > 0.05;
    const checkData = {
      timestamp: new Date().toISOString(),
      http_status: isSuccess ? 200 : (Math.random() > 0.5 ? 500 : 404),
      response_time_ms: isSuccess ? Math.floor(Math.random() * 400) + 80 : null,
      success: isSuccess,
      error_message: isSuccess ? null : "Connection Timeout"
    };

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Target URL: ${targetUrl}\nPrevious logs for context: ${JSON.stringify(logs.slice(0, 5))}\n\nNEW CHECK DATA:\n${JSON.stringify(checkData)}`,
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const analysis = JSON.parse(response.text || '{}');
      const newLog: Omit<MonitoringLog, 'id'> = {
        ...checkData,
        ai_analysis: analysis
      };

      const savedLog = await dbService.saveMonitoringLog(newLog);
      setLogs(prev => [savedLog, ...prev].slice(0, 500));

    } catch (err) {
      console.error("AI Monitoring Error:", err);
    }
  };

  useEffect(() => {
    let interval: any;
    if (isMonitoring) {
      runCheck(); 
      interval = setInterval(runCheck, frequency * 1000);
    }
    return () => clearInterval(interval);
  }, [isMonitoring, frequency, targetUrl]);

  const currentStatus = logs[0]?.ai_analysis?.status || 'UNKNOWN';

  // Prepare data for the latency chart
  const chartData = [...logs]
    .reverse()
    .slice(-30) // Show last 30 data points
    .map(log => ({
      time: new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      latency: log.response_time_ms || 0,
      status: log.ai_analysis?.status || 'UP'
    }));

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header Panel */}
      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl overflow-hidden">
        <div className="gradient-bg p-8 text-white flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-5">
            <div className={`w-16 h-16 rounded-2xl flex items-center justify-center shadow-2xl transition-all duration-500 ${isMonitoring ? 'bg-white text-indigo-600 animate-pulse' : 'bg-slate-800/50 text-slate-400'}`}>
              <Zap size={32} />
            </div>
            <div>
              <h1 className="text-3xl font-black tracking-tighter">Live Monitoring</h1>
              <div className="flex items-center gap-2">
                <p className="opacity-80 font-medium truncate max-w-[200px] md:max-w-none">{targetUrl}</p>
                <button 
                  onClick={() => setIsSettingsOpen(!isSettingsOpen)}
                  className="p-1 hover:bg-white/20 rounded-lg transition-colors"
                  title="Monitoring Settings"
                >
                  <Globe size={14} />
                </button>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsMonitoring(!isMonitoring)}
              className={`px-8 py-4 rounded-2xl font-black text-sm uppercase tracking-widest transition-all ${
                isMonitoring 
                ? 'bg-rose-500 hover:bg-rose-600 text-white shadow-lg shadow-rose-500/30' 
                : 'bg-white hover:bg-slate-50 text-indigo-600 shadow-lg shadow-black/10'
              }`}
            >
              {isMonitoring ? 'Stop Monitoring' : 'Start Monitoring'}
            </button>
          </div>
        </div>

        {/* Settings Transition */}
        {isSettingsOpen && (
          <div className="p-6 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 animate-in slide-in-from-top duration-300">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-4xl">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Globe size={12} /> Target URL
                </label>
                <input 
                  type="text" 
                  value={targetUrl}
                  onChange={(e) => setTargetUrl(e.target.value)}
                  placeholder="https://example.com"
                  className="w-full px-4 py-2.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 dark:text-white font-medium transition-all"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Timer size={12} /> Check Interval (Seconds)
                </label>
                <div className="flex items-center gap-4">
                  <input 
                    type="range" 
                    min="5" 
                    max="300" 
                    step="5"
                    value={frequency}
                    onChange={(e) => setFrequency(parseInt(e.target.value))}
                    className="flex-1 accent-indigo-600"
                  />
                  <span className="w-16 text-center font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 py-1.5 rounded-lg text-sm border border-indigo-100 dark:border-indigo-800">
                    {frequency}s
