        {/* Current Health State */}
        <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x dark:divide-slate-800">
          <div className="p-8 flex items-center gap-6">
            <div className={`w-14 h-14 rounded-full flex items-center justify-center ${currentStatus === 'UP' ? 'bg-emerald-50 text-emerald-600' : currentStatus === 'DOWN' ? 'bg-rose-50 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
