                </p>
              </div>
              <div className="p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-800">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Peak Latency</p>
                <p className="text-xl font-black text-rose-600 dark:text-rose-400">
                  {chartData.length > 0 ? Math.max(...chartData.map(d => d.latency)) : 0} ms
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

