                    <span className={`text-xs font-black ${log.success ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {log.http_status || 'ERR'}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-xs font-medium text-slate-500">
                    {log.response_time_ms ? `${log.response_time_ms}ms` : '---'}
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-xs font-semibold text-slate-600 dark:text-slate-400 truncate max-w-[300px]">
                      {log.ai_analysis?.message || '-'}
                    </p>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {(filteredReportLogs.length === 0 && logs.length === 0) && (
            <div className="py-20 text-center text-slate-400 italic font-medium">
              No historical data available. Start monitoring to populate logs.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

