      created_at: new Date().toISOString(),
    };
    setStored('system_downtime', [newEntry, ...data]);
    return newEntry;
  },
  async deleteDowntime(id: string): Promise<void> {
    const data = getStored<SystemDowntime>('system_downtime');
    setStored('system_downtime', data.filter(d => d.id !== id));
  },

  // Monitoring Logs
  /**
   * Fetches all monitoring logs from storage.
   */
  async getMonitoringLogs(): Promise<MonitoringLog[]> {
    return getStored<MonitoringLog>('monitoring_logs');
  },
  /**
   * Saves a new monitoring log entry to storage.
   */
  async saveMonitoringLog(log: Omit<MonitoringLog, 'id'>): Promise<MonitoringLog> {
    const logs = getStored<MonitoringLog>('monitoring_logs');
    const newLog: MonitoringLog = {
      ...log,
      id: Math.random().toString(36).substr(2, 9),
    };
    setStored('monitoring_logs', [newLog, ...logs]);
    return newLog;
  },
};

