import React, { useState, useEffect } from 'react';
import { dbService } from '../services/dbService';
import { SystemDowntime, SettingItem } from '../types';
import { Trash2, AlertTriangle, Calendar, Filter, Activity } from 'lucide-react';

const DowntimeReports: React.FC = () => {
  const [data, setData] = useState<SystemDowntime[]>([]);
  const [systemOptions, setSystemOptions] = useState<SettingItem[]>([]);
  const [systemFilter, setSystemFilter] = useState('All');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');

  useEffect(() => {
    loadData();
    loadSystems();
  }, []);

  const loadData = async () => {
    const records = await dbService.getDowntime();
    setData(records.sort((a, b) => b.date.localeCompare(a.date)));
  };

  const loadSystems = async () => {
    const systems = await dbService.getSettingsByCategory('system_name');
    setSystemOptions(systems);
  };

  const handleDelete = async (id: string) => {
    if (confirm('Delete this record?')) {
      await dbService.deleteDowntime(id);
      loadData();
    }
  };

  const filteredData = data.filter(d => {
    const matchesSystem = systemFilter === 'All' || d.system_name === systemFilter;
    const matchesFrom = fromDate ? d.date >= fromDate : true;
    const matchesTo = toDate ? d.date <= toDate : true;
    return matchesSystem && matchesFrom && matchesTo;
  });

  const totalDowntime = filteredData.reduce((acc, curr) => acc + curr.duration_minutes, 0);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Metrics Summary */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white dark:bg-slate-900 p-8 rounded-[2rem] border border-slate-200 dark:border-slate-800 shadow-sm">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Total Downtime</p>
          <div className="flex items-end gap-2">
            <h3 className="text-4xl font-black text-rose-600 tracking-tighter">{totalDowntime}</h3>
            <span className="text-xs font-bold text-slate-500 mb-2 uppercase tracking-widest">Min</span>
          </div>
        </div>
        <div className="bg-white dark:bg-slate-900 p-8 rounded-[2rem] border border-slate-200 dark:border-slate-800 shadow-sm">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Impact Events</p>
          <h3 className="text-4xl font-black dark:text-white tracking-tighter">{filteredData.length}</h3>
        </div>
        <div className="bg-white dark:bg-slate-900 p-8 rounded-[2rem] border border-slate-200 dark:border-slate-800 shadow-sm">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Avg Severity</p>
          <h3 className="text-4xl font-black dark:text-white tracking-tighter">
            {filteredData.length > 0 ? (totalDowntime / filteredData.length).toFixed(1) : 0} 
            <span className="text-xs font-bold text-slate-500 ml-2 uppercase tracking-widest">m</span>
          </h3>
        </div>
      </div>

      {/* Filter Toolbar */}
      <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-wrap items-center gap-4">
        <div className="flex items-center gap-3 flex-1 min-w-[240px]">
          <div className="w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-400">
            <Filter size={18} />
          </div>
          <select 
            value={systemFilter}
            onChange={(e) => setSystemFilter(e.target.value)}
            className="flex-1 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm font-bold dark:text-white outline-none focus:ring-2 focus:ring-rose-500 transition-all"
          >
            <option value="All">Filter by System: All</option>
            {systemOptions.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
          </select>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 dark:bg-slate-800 p-1.5 rounded-xl border border-slate-200 dark:border-slate-700">
          <Calendar size={16} className="text-slate-400 ml-2" />
          <input 
            type="date"
            value={fromDate}
            onChange={(e) => setFromDate(e.target.value)}
            className="bg-transparent text-xs font-bold dark:text-white outline-none"
          />
          <span className="text-slate-400 text-[10px] font-black uppercase">to</span>
          <input 
            type="date"
            value={toDate}
            onChange={(e) => setToDate(e.target.value)}
            className="bg-transparent text-xs font-bold dark:text-white outline-none mr-2"
          />
        </div>
      </div>

      {/* Table */}
      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Incident Date</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">System</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Timeframe</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Duration</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {filteredData.length > 0 ? filteredData.map(d => (
                <tr key={d.id} className="hover:bg-rose-50/10 dark:hover:bg-rose-900/5 transition-colors group">
                  <td className="px-6 py-5 text-sm font-bold text-slate-700 dark:text-slate-200">
                    {new Date(d.date).toLocaleDateString(undefined, { dateStyle: 'medium' })}
                  </td>
                  <td className="px-6 py-5">
                    <span className="text-[10px] px-2.5 py-1 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-lg font-black uppercase tracking-wider">
                      {d.system_name}
                    </span>
                  </td>
                  <td className="px-6 py-5">
                    <div className="flex items-center gap-2 text-xs font-bold text-slate-500 dark:text-slate-400">
                      <Clock size={14} />
                      {d.start_time} — {d.end_time}
                    </div>
                  </td>
                  <td className="px-6 py-5 text-center">
                    <div className="inline-flex items-center gap-2 px-3 py-1 bg-rose-50 dark:bg-rose-900/10 text-rose-600 rounded-full font-black text-[11px]">
                      {d.duration_minutes} min
                      {d.duration_minutes > 120 && <AlertTriangle size={12} className="text-rose-500 animate-pulse" />}
                    </div>
                  </td>
                  <td className="px-6 py-5 text-right">
                    <button 
                      onClick={() => handleDelete(d.id)}
                      className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-all opacity-0 group-hover:opacity-100"
                    >
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={6} className="px-6 py-20 text-center">
                    <div className="flex flex-col items-center gap-3 opacity-30">
                      <Activity size={48} />
                      <p className="text-sm font-bold uppercase tracking-widest">No matching records</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default DowntimeReports;

import React, { useState, useEffect } from 'react';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend,
  LineChart, Line, AreaChart, Area
} from 'recharts';
import { 
  AlertCircle, 
  Bug, 
  Smartphone, 
  Lightbulb, 
  HelpCircle, 
  Activity,
  ArrowUpRight,
  ArrowDownRight,
  ChevronDown
} from 'lucide-react';
import { dbService } from '../services/dbService';
import { Issue, MonthlyEntry, SystemDowntime } from '../types';
import { CHART_COLORS } from '../constants';

const Dashboard: React.FC = () => {
  const [issues, setIssues] = useState<Issue[]>([]);
  const [monthlyEntries, setMonthlyEntries] = useState<MonthlyEntry[]>([]);
  const [downtime, setDowntime] = useState<SystemDowntime[]>([]);
  const [selectedMonth, setSelectedMonth] = useState<string>(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
  });

  useEffect(() => {
    const fetchData = async () => {
      const [i, m, d] = await Promise.all([
        dbService.getIssues(),
        dbService.getMonthlyEntries(),
        dbService.getDowntime(),
      ]);
      setIssues(i);
      setMonthlyEntries(m);
      setDowntime(d);
    };
    fetchData();
  }, []);

  // Filter and process data
  const filteredIssues = issues.filter(issue => issue.created_at.startsWith(selectedMonth));
  const currentMonthlyEntry = monthlyEntries.find(e => e.month === selectedMonth);

  // Metrics
  const stats = [
    { label: 'Total Issues', value: currentMonthlyEntry?.total_issues || filteredIssues.length, icon: AlertCircle, color: 'text-indigo-600', bg: 'bg-indigo-100 dark:bg-indigo-900/20' },
    { label: 'System Bugs', value: currentMonthlyEntry?.system_bugs || filteredIssues.filter(i => i.issue_details.toLowerCase().includes('bug')).length, icon: Bug, color: 'text-rose-600', bg: 'bg-rose-100 dark:bg-rose-900/20' },
    { label: 'Device Issues', value: currentMonthlyEntry?.device_issues || filteredIssues.filter(i => i.issue_type === 'Device').length, icon: Smartphone, color: 'text-amber-600', bg: 'bg-amber-100 dark:bg-amber-900/20' },
    { label: 'Awareness', value: currentMonthlyEntry?.awareness || 0, icon: Lightbulb, color: 'text-emerald-600', bg: 'bg-emerald-100 dark:bg-emerald-900/20' },
    { label: 'Help Requests', value: currentMonthlyEntry?.help_requests || 0, icon: HelpCircle, color: 'text-sky-600', bg: 'bg-sky-100 dark:bg-sky-900/20' },
    { label: 'System Downtime', value: `${(downtime.filter(d => d.date.startsWith(selectedMonth)).reduce((acc, d) => acc + d.duration_minutes, 0) / 60).toFixed(1)}h`, icon: Activity, color: 'text-fuchsia-600', bg: 'bg-fuchsia-100 dark:bg-fuchsia-900/20' },
  ];

  // Frequent Issue Companies
  const companyCounts = filteredIssues.reduce((acc, issue) => {
    acc[issue.client_name] = (acc[issue.client_name] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  // Fix: Explicitly type the result of Object.entries to [string, number][] to avoid 'unknown' type comparison errors on line 67 and arithmetic errors on line 68.
  const frequentCompanies = (Object.entries(companyCounts) as [string, number][])
    .filter(([_, count]) => count >= 2)
    .sort((a, b) => b[1] - a[1]);

  // Chart Data
  const issueTypeData = [
    { name: 'System Bug', value: currentMonthlyEntry?.system_bugs || filteredIssues.filter(i => i.issue_details.toLowerCase().includes('bug')).length },
    { name: 'Device Issue', value: currentMonthlyEntry?.device_issues || filteredIssues.filter(i => i.issue_type === 'Device').length },
    { name: 'Awareness', value: currentMonthlyEntry?.awareness || 0 },
    { name: 'Help Request', value: currentMonthlyEntry?.help_requests || 0 },
  ].filter(d => d.value > 0);

  const statusData = ['Open', 'Close', 'Pending', 'In Progress', 'Done'].map(status => ({
    name: status,
    count: filteredIssues.filter(i => i.status === status).length
  }));

  const downtimeTimeline = downtime
    .filter(d => d.date.startsWith(selectedMonth))
    .map(d => ({
      date: d.date.split('-')[2],
      duration: d.duration_minutes,
      system: d.system_name
    }));

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Header & Filter */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Performance Overview</h1>
          <p className="text-slate-500 dark:text-slate-400">Track and analyze system health and issues</p>
        </div>
        <div className="flex items-center gap-2 bg-white dark:bg-slate-900 p-1.5 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <span className="text-xs font-bold text-slate-400 pl-2 uppercase">Period</span>
          <select 
            value={selectedMonth}
            onChange={(e) => setSelectedMonth(e.target.value)}
            className="bg-transparent text-sm font-semibold outline-none pr-2 cursor-pointer text-indigo-600"
          >
            {Array.from({ length: 12 }, (_, i) => {
              const d = new Date();
              d.setMonth(d.getMonth() - i);
              const val = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
              return (
                <option key={val} value={val}>
                  {d.toLocaleString('default', { month: 'long', year: 'numeric' })}
                </option>
              );
            })}
          </select>
        </div>
      </div>

      {/* Metrics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm hover:shadow-md transition-shadow">
            <div className={`w-10 h-10 ${stat.bg} rounded-xl flex items-center justify-center mb-4`}>
              <stat.icon size={20} className={stat.color} />
            </div>
            <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{stat.label}</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">{stat.value}</h3>
          </div>
        ))}
      </div>

      {/* Middle Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
